import sys

class Solution:
    def canRepresent(self, k):
        dp = [False] * (k + 1)
        dp[0] = True
        for i in range(1, k + 1):
            for j in range(1, i):
                if dp[j] and j + (i - j) <= k:
                    dp[i] = True
                    break
        return dp[k]

if __name__ == '__main__':
    for line in sys.stdin:
        k = int(line)
        s = Solution()
        print(s.canRepresent(k))

