#include<iostream>
#include<cstdio>

using namespace std;

class Solution {
public:
    bool canRepresent(int k) {
        bool dp[k + 1] = {false};
        dp[0] = true;
        for (int i = 1; i <= k; ++i) {
            for (int j = 1; j < i; ++j) {
                if (dp[j] && j + (i - j) <= k) {
                    dp[i] = true;
                    break;
                }
            }
        }
        return dp[k];
    }
};

int main() {
    int k;
    while (cin >> k) {
        Solution s;
        printf("%d\n", s.canRepresent(k));
    }
    return 0;
}
